// You write this:
Calendar cal = Calendar.getInstance();          // default locale
Calendar jpCal = Calendar.getInstance(japan);   // Japanese locale

// Under the hood, Calendar.getInstance() is a Factory:
// - Locale is Japan → JapaneseImperialCalendar
// - Locale is Thailand → BuddhistCalendar
// - Everything else → GregorianCalendar

// You never know (or care) which concrete class you got.

// Factory decides the formatter based on locale + style
NumberFormat nf = NumberFormat.getCurrencyInstance(Locale.US);
System.out.println(nf.format(1234.56)); // $1,234.56

NumberFormat inr = NumberFormat.getCurrencyInstance(new Locale("en", "IN"));
System.out.println(inr.format(1234.56)); // ₹1,234.56

// Same interface, different behavior based on creation input.
// This IS the Factory pattern.

// Spring's BeanFactory IS a Factory pattern:
ApplicationContext ctx = new AnnotationConfigApplicationContext(AppConfig.class);

// getBean() = Factory.create()
PaymentService svc = ctx.getBean(PaymentService.class);

// Behind the scenes:
// 1. Spring scans @Component classes (registration)
// 2. Creates instances (factory creation)
// 3. Injects dependencies (wiring)
// 4. Returns the configured bean

// Your @Service, @Repository, @Controller?
// All managed by Spring's Factory.

// You write:
Logger log = LoggerFactory.getLogger(MyService.class);

// SLF4J discovers which logging framework is on classpath:
// - Logback present → LogbackLogger
// - Log4j2 present → Log4j2Logger
// - Neither → JUL (java.util.logging)

// You code against SLF4J interface.
// Swap Logback for Log4j2? Change POM, not code.
// This is Factory pattern providing RUNTIME flexibility.

// Factory + Registry in the JDK itself
Connection conn = DriverManager.getConnection(
    "jdbc:mysql://localhost:3306/mydb", "user", "pass"
);

// How it works:
// 1. MySQL driver JAR registers itself: DriverManager.registerDriver(new MySQLDriver())
// 2. PostgreSQL driver JAR registers itself: DriverManager.registerDriver(new PGDriver())
// 3. getConnection() iterates registered drivers
// 4. First driver that accepts the URL creates the Connection

// This is the REGISTRY PATTERN inside the JDK.
// Adding a new database = add JAR to classpath. Zero code changes.

// JSX:
<Button onClick={handleClick}>Submit</Button>

// Compiles to:
React.createElement(Button, { onClick: handleClick }, "Submit")

// React.createElement IS a Factory:
// - String tag ("div") → creates DOM element
// - Function → calls it as function component
// - Class → instantiates with new + calls render()
// - Fragment → creates fragment container

// You never call new DOMElement() or new FunctionComponent()
// React's createElement Factory decides what to create.
